import React from 'react';
import { ICONS } from '../constants';
import { ExperienceItem, ProjectItem, ResumeData } from '../types';

interface ResumePaperProps {
  data: ResumeData;
}

// Helper to bold specific patterns
const highlightText = (text: string) => {
  const regex = /(\d+(?:[.,]\d+)?(?:%|x)|\$[0-9.]+[MK]?\+?)/g;
  const parts = text.split(regex);
  return parts.map((part, i) => 
    regex.test(part) ? <strong key={i} className="font-bold text-resume-primary">{part}</strong> : part
  );
};

const SectionHeader: React.FC<{ title: string; className?: string }> = ({ title, className = "mt-8" }) => (
  <div className={`flex items-center gap-3 mb-6 break-after-avoid ${className}`}>
    <h3 className="text-sm font-bold uppercase tracking-[0.2em] text-resume-primary border-b border-resume-light w-full pb-2">
      {title}
    </h3>
  </div>
);

const ExperienceBlock: React.FC<{ item: ExperienceItem }> = ({ item }) => (
  <div className="mb-8 break-inside-avoid experience-block group last:mb-0">
    <div className="flex justify-between items-baseline mb-3">
      <h4 className="font-bold text-resume-primary text-xl tracking-tight">
        {item.company} <span className="font-light text-resume-muted px-1">|</span> {item.role}
      </h4>
      <span className="text-sm font-semibold text-resume-primary whitespace-nowrap ml-4 min-w-fit">
        {item.duration}
      </span>
    </div>

    <ul className="space-y-2">
      {item.highlights.map((h, idx) => (
        <li key={idx} className="text-[13.5px] text-resume-secondary leading-[1.6] relative pl-0">
